use crate::object::RObject;
use crate::types::*;

/// Trait for combining (concatenating) R objects
pub trait Combine {
    /// The output type after combination
    type Output;

    /// Combine this object with another
    fn combine(&self, other: &Self) -> Self::Output;
}

/// Implementation of Combine for Vector types
impl<T: Clone> Combine for Vector<T> {
    type Output = Vector<T>;

    fn combine(&self, other: &Self) -> Self::Output {
        let mut result = self.values.clone();
        result.extend(other.values.clone());
        Vector { values: result }
    }
}

/// Implementation of Combine for List
impl Combine for List {
    type Output = List;

    fn combine(&self, other: &Self) -> Self::Output {
        let mut result = self.elements.clone();
        result.extend(other.elements.clone());
        List { elements: result }
    }
}

/// Implementation of Combine for DataFrame
impl Combine for DataFrame {
    type Output = Result<DataFrame, String>;

    fn combine(&self, other: &Self) -> Self::Output {
        // For DataFrames, we need to ensure column names match
        if self.columns.keys().ne(other.columns.keys()) {
            return Err("Column names must match to combine DataFrames".to_string());
        }

        let mut combined_columns = std::collections::HashMap::new();

        for (name, col) in &self.columns {
            let self_col = col.as_any().downcast_ref::<Vector<f64>>()
                .or_else(|| col.as_any().downcast_ref::<Vector<i32>>())
                .or_else(|| col.as_any().downcast_ref::<Vector<String>>())
                .or_else(|| col.as_any().downcast_ref::<Vector<bool>>());

            let other_col = other.columns.get(name)
                .and_then(|c| c.as_any().downcast_ref::<Vector<f64>>()
                    .or_else(|| c.as_any().downcast_ref::<Vector<i32>>())
                    .or_else(|| c.as_any().downcast_ref::<Vector<String>>())
                    .or_else(|| c.as_any().downcast_ref::<Vector<bool>>()));

            match (self_col, other_col) {
                (Some(s), Some(o)) if std::any::type_name_of_val(s) == std::any::type_name_of_val(o) => {
                    // Same types, can combine
                    if let Some(s_f64) = col.as_any().downcast_ref::<Vector<f64>>() {
                        if let Some(o_f64) = other.columns.get(name).unwrap().as_any().downcast_ref::<Vector<f64>>() {
                            combined_columns.insert(name.clone(), Box::new(s_f64.combine(o_f64)));
                        }
                    } else if let Some(s_i32) = col.as_any().downcast_ref::<Vector<i32>>() {
                        if let Some(o_i32) = other.columns.get(name).unwrap().as_any().downcast_ref::<Vector<i32>>() {
                            combined_columns.insert(name.clone(), Box::new(s_i32.combine(o_i32)));
                        }
                    } else if let Some(s_str) = col.as_any().downcast_ref::<Vector<String>>() {
                        if let Some(o_str) = other.columns.get(name).unwrap().as_any().downcast_ref::<Vector<String>>() {
                            combined_columns.insert(name.clone(), Box::new(s_str.combine(o_str)));
                        }
                    } else if let Some(s_bool) = col.as_any().downcast_ref::<Vector<bool>>() {
                        if let Some(o_bool) = other.columns.get(name).unwrap().as_any().downcast_ref::<Vector<bool>>() {
                            combined_columns.insert(name.clone(), Box::new(s_bool.combine(o_bool)));
                        }
                    }
                }
                _ => return Err(format!("Column '{}' has incompatible types", name)),
            }
        }

        Ok(DataFrame { columns: combined_columns })
    }
}

/// Helper function for combining vectors with NA handling
pub fn combine_with_na<T: Clone>(v1: &Vector<Option<T>>, v2: &Vector<Option<T>>) -> Vector<Option<T>> {
    let mut result = v1.values.clone();
    result.extend(v2.values.clone());
    Vector { values: result }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_vector_combine() {
        let v1 = Vector { values: vec![1, 2, 3] };
        let v2 = Vector { values: vec![4, 5, 6] };
        let combined = v1.combine(&v2);
        assert_eq!(combined.values, vec![1, 2, 3, 4, 5, 6]);
    }

    #[test]
    fn test_list_combine() {
        let l1 = List { 
            elements: vec![
                Box::new(Vector { values: vec![1.0] }),
                Box::new(Vector { values: vec!["a".to_string()] })
            ]
        };
        let l2 = List { 
            elements: vec![
                Box::new(Vector { values: vec![2.0] })
            ]
        };
        let combined = l1.combine(&l2);
        assert_eq!(combined.elements.len(), 3);
    }

    #[test]
    fn test_dataframe_combine() {
        let mut cols1 = std::collections::HashMap::new();
        cols1.insert("x".to_string(), Box::new(Vector { values: vec![1, 2] }) as Box<dyn RObject>);
        cols1.insert("y".to_string(), Box::new(Vector { values: vec![3.0, 4.0] }) as Box<dyn RObject>);

        let mut cols2 = std::collections::HashMap::new();
        cols2.insert("x".to_string(), Box::new(Vector { values: vec![5, 6] }) as Box<dyn RObject>);
        cols2.insert("y".to_string(), Box::new(Vector { values: vec![7.0, 8.0] }) as Box<dyn RObject>);

        let df1 = DataFrame { columns: cols1 };
        let df2 = DataFrame { columns: cols2 };

        let combined = df1.combine(&df2).unwrap();

        let x_col = combined.columns.get("x").unwrap().as_any().downcast_ref::<Vector<i32>>().unwrap();
        assert_eq!(x_col.values, vec![1, 2, 5, 6]);

        let y_col = combined.columns.get("y").unwrap().as_any().downcast_ref::<Vector<f64>>().unwrap();
        assert_eq!(y_col.values, vec![3.0, 4.0, 7.0, 8.0]);
    }

    #[test]
    fn test_dataframe_combine_mismatch() {
        let mut cols1 = std::collections::HashMap::new();
        cols1.insert("x".to_string(), Box::new(Vector { values: vec![1, 2] }) as Box<dyn RObject>);

        let mut cols2 = std::collections::HashMap::new();
        cols2.insert("y".to_string(), Box::new(Vector { values: vec![3, 4] }) as Box<dyn RObject>);

        let df1 = DataFrame { columns: cols1 };
        let df2 = DataFrame { columns: cols2 };

        assert!(df1.combine(&df2).is_err());
    }
}

