/// Implementation of Combine for Vector types
impl<T: Clone> Combine for Vector<T> {
    type Output = Vector<T>;

    fn combine(&self, other: &Self) -> Self::Output {
        let mut result = self.values.clone();
        result.extend(other.values.clone());
        Vector { values: result }
    }
}

/// Implementation of Combine for List
