use crate::types::*;

/// Trait for combining (concatenating) R objects
pub trait Combine {
    /// The output type after combination
    type Output;

    /// Combine this object with another
    fn combine(&self, other: &Self) -> Self::Output;
}

/// Implementation of Combine for Vector types
impl<T: Clone> Combine for Vector<T> {
    type Output = Vector<T>;

    fn combine(&self, other: &Self) -> Self::Output {
        let mut result = self.values.clone();
        result.extend(other.values.clone());
        Vector { values: result }
    }
}

/// Implementation of Combine for List
impl Combine for List {
    type Output = List;

    fn combine(&self, other: &Self) -> Self::Output {
        let mut result = self.elements.clone();
        result.extend(other.elements.clone());
        List { elements: result }
    }
}

/// Implementation of Combine for DataFrame
impl Combine for DataFrame {
    type Output = Result<DataFrame, String>;

    fn combine(&self, other: &Self) -> Self::Output {
        use crate::object::RObject;

        // For DataFrames, we need to ensure column names match
        if self.columns.keys().ne(other.columns.keys()) {
            return Err("Column names must match to combine DataFrames".to_string());
        }

        let mut combined_columns = std::collections::HashMap::new();

        for (name, col) in &self.columns {
            let other_col = other.columns.get(name).unwrap();

            // Try to downcast and combine for each type
            if let Some(s_f64) = col.as_any().downcast_ref::<Vector<f64>>() {
                if let Some(o_f64) = other_col.as_any().downcast_ref::<Vector<f64>>() {
                    combined_columns.insert(name.clone(), Box::new(s_f64.combine(o_f64)) as Box<dyn RObject>);
                } else {
                    return Err(format!("Column '{}' has incompatible types", name));
                }
            } else if let Some(s_i32) = col.as_any().downcast_ref::<Vector<i32>>() {
                if let Some(o_i32) = other_col.as_any().downcast_ref::<Vector<i32>>() {
                    combined_columns.insert(name.clone(), Box::new(s_i32.combine(o_i32)) as Box<dyn RObject>);
                } else {
                    return Err(format!("Column '{}' has incompatible types", name));
                }
            } else if let Some(s_str) = col.as_any().downcast_ref::<Vector<String>>() {
                if let Some(o_str) = other_col.as_any().downcast_ref::<Vector<String>>() {
                    combined_columns.insert(name.clone(), Box::new(s_str.combine(o_str)) as Box<dyn RObject>);
                } else {
                    return Err(format!("Column '{}' has incompatible types", name));
                }
            } else if let Some(s_bool) = col.as_any().downcast_ref::<Vector<bool>>() {
                if let Some(o_bool) = other_col.as_any().downcast_ref::<Vector<bool>>() {
                    combined_columns.insert(name.clone(), Box::new(s_bool.combine(o_bool)) as Box<dyn RObject>);
                } else {
                    return Err(format!("Column '{}' has incompatible types", name));
                }
            } else {
                return Err(format!("Column '{}' has unsupported type", name));
            }
        }

        Ok(DataFrame { columns: combined_columns })
    }
}

